module booth_radix4(
input	[2:0]codes,
output	zero,
output	double,
output	negation
);
wire	obf_A;
assign	obf_A=codes[2];
wire	B;
assign	B=codes[1];
wire	C;
assign	C=codes[0];
wire	nB,nC,nA;
assign	nB=~B;
assign	nC=~C;
assign	nA=~obf_A;
wire	BC;
assign	BC=B&C;
wire	nBnC;
assign	nBnC=nB&nC;
wire	nBanC;
assign	nBanC=nB|nC;
assign	double=(nBnC&obf_A)|(BC&nA);
assign	negation=obf_A&nBanC;
assign	zero=(obf_A&BC)|(nA&nBnC);
endmodule
